  FOR rec IN SELECT * FROM tmp_enc_import ORDER BY old_id LOOP
    CASE rec.old_condo_id
      WHEN 41 THEN v_condo_id := v_condo_montserrat;
      WHEN 42 THEN v_condo_id := v_condo_recanto;
      ELSE v_condo_id := NULL;
    END CASE;

    IF v_condo_id IS NULL THEN v_skipped := v_skipped + 1; CONTINUE; END IF;

    SELECT id INTO v_user_id FROM public.perfil
      WHERE condominio_id = v_condo_id
        AND UPPER(TRIM(bloco_txt)) = UPPER(TRIM(rec.bloco))
        AND TRIM(apto_txt) = TRIM(rec.apto)
      ORDER BY created_at DESC LIMIT 1;

    IF v_user_id IS NULL THEN
      v_skipped := v_skipped + 1;
      RAISE NOTICE 'SKIP old_id=% bloco=% apto=% condo=%', rec.old_id, rec.bloco, rec.apto, rec.old_condo_id;
      CONTINUE;
    END IF;

      resident_id, condominio_id, status, arrival_time,
      photo_url, tipo, tracking_code, observacao, created_at
    ) VALUES (
      v_user_id, v_condo_id, 'pending', rec.created_at,
      rec.photo_url, rec.tipo, rec.tracking_code, rec.observacao, rec.created_at
    );
    v_count := v_count + 1;
  END LOOP;

  DROP TABLE tmp_enc_import;
  RAISE NOTICE 'PART 4/7 DONE: % imported, % skipped', v_count, v_skipped;
END $$;
